 86→    public static class TopologyVersion {
 87→        public AtomicLong topologyVersion = new AtomicLong(0L); // the local topology version
 88→        public ReentrantLock topologyLock = new ReentrantLock();
 89→        public Condition topologyCV = topologyLock.newCondition();
 90→        public List<TopologyVersionListener> activeTopologyUpdateListeners = new LinkedList<>();
