194→    public void maybeNotifyTopologyVersionListeners() {
195→        try {
196→            lock();
197→            final long minThreadVersion = minimumThreadVersion();
198→            final Iterator<TopologyVersionListener> iterator = version.activeTopologyUpdateListeners.listIterator();
199→            TopologyVersionListener topologyVersionListener;
200→            while (iterator.hasNext()) {
201→                topologyVersionListener = iterator.next();
202→                final long topologyVersionWaitersVersion = topologyVersionListener.topologyVersion;
203→                if (minThreadVersion >= topologyVersionWaitersVersion) {
204→                    topologyVersionListener.future.complete(null);
205→                    iterator.remove();
206→                    log.info("All threads are now on topology version {}", topologyVersionListener.topologyVersion);
207→                }
208→            }
209→        } finally {
210→            unlock();
211→        }
212→    }
