 39→class NamedCache {
 40→    private static final Logger log = LoggerFactory.getLogger(NamedCache.class);
 41→    private final String name;
 42→    private final String storeName;
 43→    private final String taskName;
 44→    private final NavigableMap<Bytes, LRUNode> cache = new TreeMap<>();
 45→    private final Set<Bytes> dirtyKeys = new LinkedHashSet<>();
 46→    private ThreadCache.DirtyEntryFlushListener listener;
 47→    private LRUNode tail;
 48→    private LRUNode head;
 49→    private long currentSizeBytes;
 50→
 51→    private final StreamsMetricsImpl streamsMetrics;
 52→    private final Sensor hitRatioSensor;
 53→    private final Sensor totalCacheSizeSensor;
 54→
 55→    // internal stats
 56→    private long numReadHits = 0;
 57→    private long numReadMisses = 0;
 58→    private long numOverwrites = 0;
 59→    private long numFlushes = 0;
 60→
 61→    NamedCache(final String name, final StreamsMetricsImpl streamsMetrics) {
 62→        this.name = name;
 63→        this.streamsMetrics = streamsMetrics;
 64→        storeName = ThreadCache.underlyingStoreNamefromCacheName(name);
 65→        taskName = ThreadCache.taskIDfromCacheName(name);
 66→        hitRatioSensor = NamedCacheMetrics.hitRatioSensor(
 67→            streamsMetrics,
 68→            Thread.currentThread().getName(),
 69→            taskName,
 70→            storeName
 71→        );
 72→        totalCacheSizeSensor = TaskMetrics.totalCacheSizeBytesSensor(
 73→                Thread.currentThread().getName(),
 74→                taskName,
 75→                streamsMetrics
 76→        );
 77→    }
 78→
 79→    final synchronized String name() {
 80→        return name;
 81→    }
 82→
 83→    synchronized long hits() {
 84→        return numReadHits;
 85→    }
 86→
 87→    synchronized long misses() {
 88→        return numReadMisses;
 89→    }
 90→
 91→    synchronized long overwrites() {
 92→        return numOverwrites;
 93→    }
 94→
 95→    synchronized long flushes() {
 96→        return numFlushes;
 97→    }
 98→
 99→    synchronized LRUCacheEntry get(final Bytes key) {
100→        if (key == null) {
101→            return null;
102→        }
103→
104→        final LRUNode node = getInternal(key);
105→        if (node == null) {
106→            return null;
107→        }
108→        updateLRU(node);
109→        return node.entry;
110→    }
111→
112→    synchronized void setListener(final ThreadCache.DirtyEntryFlushListener listener) {
113→        this.listener = listener;
114→    }
115→
116→    synchronized void flush() {
117→        flush(null);
118→    }
119→
120→    private void flush(final LRUNode evicted) {
121→        numFlushes++;
122→
123→        if (log.isTraceEnabled()) {
124→            log.trace("Named cache {} stats on flush: #hits={}, #misses={}, #overwrites={}, #flushes={}",
125→                name, hits(), misses(), overwrites(), flushes());
126→        }
127→
128→        if (listener == null) {
129→            throw new IllegalArgumentException("No listener for namespace " + name + " registered with cache");
130→        }
131→
132→        if (dirtyKeys.isEmpty()) {
133→            return;
134→        }
135→
136→        final List<ThreadCache.DirtyEntry> entries = new ArrayList<>();
137→        final List<Bytes> deleted = new ArrayList<>();
138→
139→        // evicted already been removed from the cache so add it to the list of
140→        // flushed entries and remove from dirtyKeys.
141→        if (evicted != null) {
142→            entries.add(new ThreadCache.DirtyEntry(evicted.key, evicted.entry.value(), evicted.entry));
143→            dirtyKeys.remove(evicted.key);
144→        }
145→
146→        for (final Bytes key : dirtyKeys) {
147→            final LRUNode node = getInternal(key);
148→            if (node == null) {
149→                throw new IllegalStateException("Key = " + key + " found in dirty key set, but entry is null");
150→            }
151→            entries.add(new ThreadCache.DirtyEntry(key, node.entry.value(), node.entry));
152→            node.entry.markClean();
153→            if (node.entry.value() == null) {
154→                deleted.add(node.key);
155→            }
156→        }
157→        // clear dirtyKeys before the listener is applied as it may be re-entrant.
158→        dirtyKeys.clear();
159→        listener.apply(entries);
160→        for (final Bytes key : deleted) {
161→            delete(key);
162→        }
163→    }
164→
165→    synchronized void put(final Bytes key, final LRUCacheEntry value) {
166→        if (!value.isDirty() && dirtyKeys.contains(key)) {
167→            throw new IllegalStateException(
168→                String.format(
169→                    "Attempting to put a clean entry for key [%s] into NamedCache [%s] when it already contains a dirty entry for the same key",
170→                    key, name
171→                )
172→            );
173→        }
174→        LRUNode node = cache.get(key);
175→        if (node != null) {
176→            numOverwrites++;
177→
178→            currentSizeBytes -= node.size();
179→            node.update(value);
180→            updateLRU(node);
181→        } else {
182→            node = new LRUNode(key, value);
183→            // put element
184→            putHead(node);
185→            cache.put(key, node);
186→        }
187→        if (value.isDirty()) {
188→            // first remove and then add so we can maintain ordering as the arrival order of the records.
189→            dirtyKeys.remove(key);
190→            dirtyKeys.add(key);
191→        }
192→        currentSizeBytes += node.size();
193→        totalCacheSizeSensor.record(currentSizeBytes);
194→    }
195→
196→    synchronized long sizeInBytes() {
197→        return currentSizeBytes;
198→    }
199→
200→    private LRUNode getInternal(final Bytes key) {
201→        final LRUNode node = cache.get(key);
202→        if (node == null) {
203→            numReadMisses++;
204→
205→            return null;
206→        } else {
207→            numReadHits++;
208→            hitRatioSensor.record((double) numReadHits / (double) (numReadHits + numReadMisses));
209→        }
210→        return node;
211→    }
212→
213→    private void updateLRU(final LRUNode node) {
214→        remove(node);
215→
216→        putHead(node);
217→    }
218→
219→    private void remove(final LRUNode node) {
220→        if (node.previous != null) {
221→            node.previous.next = node.next;
222→        } else {
223→            head = node.next;
224→        }
225→        if (node.next != null) {
226→            node.next.previous = node.previous;
227→        } else {
228→            tail = node.previous;
229→        }
230→    }
231→
232→    private void putHead(final LRUNode node) {
233→        node.next = head;
234→        node.previous = null;
235→        if (head != null) {
236→            head.previous = node;
237→        }
238→        head = node;
239→        if (tail == null) {
240→            tail = head;
241→        }
242→    }
243→
244→    synchronized void evict() {
245→        if (tail == null) {
246→            return;
247→        }
248→        final LRUNode eldest = tail;
249→        currentSizeBytes -= eldest.size();
250→        remove(eldest);
251→        cache.remove(eldest.key);
252→        if (eldest.entry.isDirty()) {
253→            flush(eldest);
254→        }
255→        totalCacheSizeSensor.record(currentSizeBytes);
256→    }
257→
258→    synchronized LRUCacheEntry putIfAbsent(final Bytes key, final LRUCacheEntry value) {
259→        final LRUCacheEntry originalValue = get(key);
260→        if (originalValue == null) {
261→            put(key, value);
262→        }
263→        return originalValue;
264→    }
265→
266→    synchronized void putAll(final List<KeyValue<byte[], LRUCacheEntry>> entries) {
267→        for (final KeyValue<byte[], LRUCacheEntry> entry : entries) {
268→            put(Bytes.wrap(entry.key), entry.value);
269→        }
270→    }
271→
272→    synchronized LRUCacheEntry delete(final Bytes key) {
273→        final LRUNode node = cache.remove(key);
274→
275→        if (node == null) {
276→            return null;
277→        }
278→
279→        remove(node);
280→        dirtyKeys.remove(key);
281→        currentSizeBytes -= node.size();
282→        totalCacheSizeSensor.record(currentSizeBytes);
283→        return node.entry();
284→    }
285→
286→    public long size() {
287→        return cache.size();
288→    }
289→
290→    public boolean isEmpty() {
291→        return cache.isEmpty();
292→    }
293→
294→    synchronized Iterator<Bytes> keyRange(final Bytes from, final Bytes to, final boolean toInclusive) {
295→        final Set<Bytes> rangeSet = computeSubSet(from, to, toInclusive);
296→        return keySetIterator(rangeSet, true);
297→    }
298→
299→    synchronized Iterator<Bytes> reverseKeyRange(final Bytes from, final Bytes to) {
300→        final Set<Bytes> rangeSet = computeSubSet(from, to, true);
301→        return keySetIterator(rangeSet, false);
302→    }
303→
304→    private Set<Bytes> computeSubSet(final Bytes from, final Bytes to, final boolean toInclusive) {
305→        if (from == null && to == null) {
306→            return cache.navigableKeySet();
307→        } else if (from == null) {
308→            return cache.headMap(to, toInclusive).keySet();
309→        } else if (to == null) {
310→            return cache.tailMap(from, true).keySet();
311→        } else if (from.compareTo(to) > 0) {
312→            return Collections.emptyNavigableSet();
313→        } else {
314→            return cache.navigableKeySet().subSet(from, true, to, toInclusive);
315→        }
316→    }
317→
318→    private Iterator<Bytes> keySetIterator(final Set<Bytes> keySet, final boolean forward) {
319→        if (forward) {
320→            return new TreeSet<>(keySet).iterator();
321→        } else {
322→            return new TreeSet<>(keySet).descendingIterator();
323→        }
324→    }
325→
326→    synchronized Iterator<Bytes> allKeys() {
327→        return keySetIterator(cache.navigableKeySet(), true);
328→    }
329→
330→    synchronized Iterator<Bytes> reverseAllKeys() {
331→        return keySetIterator(cache.navigableKeySet(), false);
332→    }
333→
334→    synchronized LRUCacheEntry first() {
335→        if (head == null) {
336→            return null;
337→        }
338→        return head.entry;
339→    }
340→
341→    synchronized LRUCacheEntry last() {
342→        if (tail == null) {
343→            return null;
344→        }
345→        return tail.entry;
346→    }
347→
348→    synchronized LRUNode head() {
349→        return head;
350→    }
351→
352→    synchronized LRUNode tail() {
353→        return tail;
354→    }
355→
356→    synchronized void close() {
357→        head = tail = null;
358→        listener = null;
359→        currentSizeBytes = 0;
360→        dirtyKeys.clear();
361→        cache.clear();
362→        streamsMetrics.removeAllCacheLevelSensors(Thread.currentThread().getName(), taskName, storeName);
363→    }
364→
365→    synchronized void clear() {
366→        head = tail = null;
367→        currentSizeBytes = 0;
368→        dirtyKeys.clear();
369→        cache.clear();
370→    }
