372→    /**
373→     * A simple wrapper class to implement a doubly-linked list around MemoryLRUCacheBytesEntry
374→     */
375→    static class LRUNode {
376→        private final Bytes key;
377→        private LRUCacheEntry entry;
378→        private LRUNode previous;
379→        private LRUNode next;
380→
381→        LRUNode(final Bytes key, final LRUCacheEntry entry) {
382→            this.key = key;
383→            this.entry = entry;
384→        }
385→
386→        LRUCacheEntry entry() {
387→            return entry;
388→        }
389→
390→        Bytes key() {
391→            return key;
392→        }
393→
394→        long size() {
395→            return key.get().length +
396→                8 + // entry
397→                8 + // previous
398→                8 + // next
399→                entry.size();
400→        }
401→
402→        LRUNode next() {
403→            return next;
404→        }
405→
406→        LRUNode previous() {
407→            return previous;
408→        }
409→
410→        private void update(final LRUCacheEntry entry) {
411→            this.entry = entry;
412→        }
413→    }
