 47→/**
 48→ * An active task could only be in one of the following status:
 49→ *
 50→ * 1. It's assigned to one of the executors for processing.
 51→ * 2. It's locked for committing, removal, other manipulations etc.
 52→ * 3. Neither 1 or 2, i.e. it stays idle. This is possible if we do not have enough executors or because those tasks
 53→ *    are not processable (e.g. because no records fetched) yet.
 54→ */
 55→public final class DefaultTaskManager implements TaskManager {
 56→
 57→    private final Time time;
 58→    private final Logger log;
 59→    private final TasksRegistry tasks;
 60→    private final TopologyMetadata topologyMetadata;
 61→
 62→    private final Lock tasksLock = new ReentrantLock();
 63→    private final Condition tasksCondition = tasksLock.newCondition();
 64→    private final List<TaskId> lockedTasks = new ArrayList<>();
 65→    private final Map<TaskId, StreamsException> uncaughtExceptions = new HashMap<>();
 66→    private final Map<TaskId, TaskExecutor> assignedTasks = new HashMap<>();
 67→    private final TaskExecutionMetadata taskExecutionMetadata;
 68→
 69→    private final List<TaskExecutor> taskExecutors;
 70→
 71→    public static class DefaultTaskExecutorCreator implements TaskExecutorCreator {
 72→        @Override
 73→        public TaskExecutor create(final TaskManager taskManager, final String name, final Time time, final TaskExecutionMetadata taskExecutionMetadata) {
 74→            return new DefaultTaskExecutor(taskManager, name, time, taskExecutionMetadata);
 75→        }
 76→    }
 77→
 78→    public DefaultTaskManager(final Time time,
 79→                              final String clientId,
 80→                              final TasksRegistry tasks,
 81→                              final TaskExecutorCreator executorCreator,
 82→                              final TaskExecutionMetadata taskExecutionMetadata,
 83→                              final int numExecutors,
 84→                              final TopologyMetadata topologyMetadata
 85→                              ) {
 86→        final String logPrefix = String.format("%s ", clientId);
 87→        final LogContext logContext = new LogContext(logPrefix);
 88→        this.log = logContext.logger(DefaultTaskManager.class);
 89→        this.time = time;
 90→        this.tasks = tasks;
 91→        this.taskExecutionMetadata = taskExecutionMetadata;
 92→        this.topologyMetadata = topologyMetadata;
 93→        topologyMetadata.registerLifecycleObserver(new TaskTopologyObserver());
 94→
 95→        this.taskExecutors = new ArrayList<>(numExecutors);
 96→        for (int i = 1; i <= numExecutors; i++) {
 97→            final String name = clientId + "-TaskExecutor-" + i;
 98→            this.taskExecutors.add(executorCreator.create(this, name, time, taskExecutionMetadata));
 99→        }
100→    }
101→
102→    private class TaskTopologyObserver implements TopologyMetadata.TopologyLifecycleObserver {
103→        @Override
104→        public void onTopologyChange(final long newVersion, final Set<String> activeTopologies) {
105→            validateTopologyConsistency(activeTopologies);
106→        }
107→    }
108→
109→    private void validateTopologyConsistency(final Set<String> activeTopologies) {
110→        executeWithTasksLocked(() -> {
111→            for (final StreamTask task : tasks.activeInitializedTasks()) {
112→                final String topologyName = task.id().topologyName();
113→                if (topologyName != null && !activeTopologies.contains(topologyName)) {
114→                    log.warn("Task {} belongs to topology {} which is no longer active", task.id(), topologyName);
115→                }
116→            }
117→        });
118→    }
119→
120→    @Override
121→    public StreamTask assignNextTask(final TaskExecutor executor) {
122→        return returnWithTasksLocked(() -> {
123→            if (!taskExecutors.contains(executor)) {
124→                throw new IllegalArgumentException("The requested executor for getting next task to assign is unrecognized");
125→            }
126→
127→            // the most naive scheduling algorithm for now: give the next unlocked, unassigned, and  processable task
128→            for (final StreamTask task : tasks.activeInitializedTasks()) {
129→                if (topologyMetadata.isTaskTopologyStale(task.id())) {
130→                    continue;
131→                }
132→                if (!assignedTasks.containsKey(task.id()) &&
133→                    !lockedTasks.contains(task.id()) &&
134→                    canProgress(task, time.milliseconds()) &&
135→                    !hasUncaughtException(task.id())
136→                ) {
137→
138→                    assignedTasks.put(task.id(), executor);
139→
140→                    log.debug("Assigned task {} to executor {}", task.id(), executor.name());
141→
142→                    return task;
143→                }
144→            }
145→
146→            log.debug("Found no assignable task for executor {}", executor.name());
147→
148→            return null;
149→        });
150→    }
151→
152→    @Override
153→    public void awaitProcessableTasks(final Supplier<Boolean> isShuttingDown) throws InterruptedException {
154→        final boolean interrupted = returnWithTasksLocked(() -> {
155→            for (final StreamTask task : tasks.activeInitializedTasks()) {
156→                if (!assignedTasks.containsKey(task.id()) &&
157→                    !lockedTasks.contains(task.id()) &&
158→                    canProgress(task, time.milliseconds()) &&
159→                    !hasUncaughtException(task.id())
160→                ) {
161→                    log.debug("Await unblocked: returning early from await since a processable task {} was found", task.id());
162→                    return false;
163→                }
164→            }
165→            try {
166→                // We re-check the shutdownRequest atomic boolean to avoid a race condition. If this thread was
167→                // previously interrupted while awaiting tasksCondition, it is possible to miss the signalAll that
168→                // is called during shutdown. If this happens, we end up blocking in the await forever.
169→                if (!isShuttingDown.get()) {
170→                    log.debug("Await blocking");
171→                    tasksCondition.await();
172→                } else {
173→                    log.debug("Not awaiting since shutdown was requested");
174→                }
175→            } catch (final InterruptedException ignored) {
176→                // we interrupt the thread for shut down and pause.
177→                // we can ignore this exception.
178→                log.debug("Await unblocked: Interrupted while waiting for processable tasks");
179→                return true;
180→            }
181→            log.debug("Await unblocked: Woken up to check for processable tasks");
182→            return false;
183→        });
184→
185→        if (interrupted) {
186→            throw new InterruptedException();
187→        }
188→    }
189→
190→    public void signalTaskExecutors() {
191→        log.debug("Waking up task executors");
192→        executeWithTasksLocked(tasksCondition::signalAll);
193→    }
194→
195→    @Override
196→    public void unassignTask(final StreamTask task, final TaskExecutor executor) {
197→        executeWithTasksLocked(() -> {
198→            if (!taskExecutors.contains(executor)) {
199→                throw new IllegalArgumentException("The requested executor for unassign task is unrecognized");
200→            }
201→
202→            final TaskExecutor lockedExecutor = assignedTasks.get(task.id());
203→            if (lockedExecutor == null || lockedExecutor != executor) {
204→                throw new IllegalArgumentException("Task " + task.id() + " is not locked by the executor");
205→            }
206→
207→            assignedTasks.remove(task.id());
208→
209→            log.debug("Unassigned {} from executor {}", task.id(), executor.name());
210→            tasksCondition.signalAll();
211→        });
212→    }
213→
214→    @Override
215→    public KafkaFuture<Void> lockTasks(final Set<TaskId> taskIds) {
216→        final KafkaFutureImpl<Void> result = new KafkaFutureImpl<>();
217→
218→        if (taskIds.isEmpty()) {
219→            result.complete(null);
220→            return result;
221→        }
222→
223→        return returnWithTasksLocked(() -> {
224→            lockedTasks.addAll(taskIds);
225→
226→            final Set<TaskId> remainingTaskIds = new ConcurrentSkipListSet<>(taskIds);
227→
228→            for (final TaskId taskId : taskIds) {
229→                final Task task = tasks.initializedTask(taskId);
230→
231→                if (task == null) {
232→                    throw new IllegalArgumentException("Trying to lock task " + taskId + " but it's not owned");
233→                }
234→
235→                if (!task.isActive()) {
236→                    throw new IllegalArgumentException("The locking task " + taskId + " is not an active task");
237→                }
238→
239→                if (assignedTasks.containsKey(taskId)) {
240→                    final TaskExecutor executor = assignedTasks.get(taskId);
241→                    log.debug("Requesting release of task {} from {}", taskId, executor.name());
242→                    final KafkaFuture<StreamTask> future = executor.unassign();
243→                    future.whenComplete((streamTask, throwable) -> {
244→                        if (throwable != null) {
245→                            result.completeExceptionally(throwable);
246→                        } else {
247→                            assert !assignedTasks.containsKey(taskId);
248→                            // It can happen that the executor handed back the task before we asked it to
249→                            // in which case `streamTask` will be null here.
250→                            assert streamTask == null || streamTask.id() == taskId;
251→                            remainingTaskIds.remove(taskId);
252→                            if (remainingTaskIds.isEmpty()) {
253→                                result.complete(null);
254→                            }
255→                        }
256→                    });
257→                } else {
258→                    remainingTaskIds.remove(taskId);
259→                    if (remainingTaskIds.isEmpty()) {
260→                        result.complete(null);
261→                    }
262→                }
263→            }
264→
265→            return result;
266→        });
267→    }
268→
269→    @Override
270→    public KafkaFuture<Void> lockAllTasks() {
271→        return returnWithTasksLocked(() ->
272→            lockTasks(tasks.activeInitializedTasks().stream().map(Task::id).collect(Collectors.toSet()))
273→        );
274→    }
275→
276→    @Override
277→    public void unlockTasks(final Set<TaskId> taskIds) {
278→
279→        if (taskIds.isEmpty()) {
280→            return;
281→        }
282→
283→        executeWithTasksLocked(() -> {
284→            lockedTasks.removeAll(taskIds);
285→            log.debug("Waking up task executors");
286→            tasksCondition.signalAll();
287→        });
288→    }
289→
290→    @Override
291→    public void unlockAllTasks() {
292→        executeWithTasksLocked(() -> unlockTasks(tasks.activeInitializedTasks().stream().map(Task::id).collect(Collectors.toSet())));
293→    }
294→
295→    @Override
296→    public void add(final Set<StreamTask> tasksToAdd) {
297→        executeWithTasksLocked(() -> {
298→            for (final StreamTask task : tasksToAdd) {
299→                tasks.addActiveTask(task);
300→            }
301→            log.debug("Waking up task executors");
302→            tasksCondition.signalAll();
303→        });
304→
305→        log.info("Added tasks {} to the task manager to process", tasksToAdd);
306→    }
307→
308→    @Override
309→    public void remove(final TaskId taskId) {
310→        executeWithTasksLocked(() -> {
311→            if (assignedTasks.containsKey(taskId)) {
312→                throw new IllegalArgumentException("The task to remove is still assigned to executors");
313→            }
314→
315→            if (!lockedTasks.contains(taskId)) {
316→                throw new IllegalArgumentException("The task to remove is not locked yet by the task manager");
317→            }
318→
319→            if (!tasks.containsInitialized(taskId)) {
320→                throw new IllegalArgumentException("The task to remove is not owned by the task manager");
321→            }
322→
323→            tasks.removeTask(tasks.initializedTask(taskId));
324→        });
325→
326→        log.info("Removed task {} from the task manager", taskId);
327→    }
328→
329→    @Override
330→    public Set<ReadOnlyTask> getTasks() {
331→        return returnWithTasksLocked(() -> tasks.activeInitializedTasks().stream().map(ReadOnlyTask::new).collect(Collectors.toSet()));
332→    }
333→
334→    @Override
335→    public void setUncaughtException(final StreamsException exception, final TaskId taskId) {
336→        executeWithTasksLocked(() -> {
337→
338→            if (!assignedTasks.containsKey(taskId)) {
339→                throw new IllegalArgumentException("An uncaught exception can only be set as long as the task is still assigned");
340→            }
341→
342→            if (uncaughtExceptions.containsKey(taskId)) {
343→                throw new IllegalArgumentException("The uncaught exception must be cleared before restarting processing");
344→            }
345→
346→            uncaughtExceptions.put(taskId, exception);
347→        });
348→
349→        log.info("Set an uncaught exception of type {} for task {}, with error message: {}",
350→            exception.getClass().getName(),
351→            taskId,
352→            exception.getMessage());
353→    }
354→
355→    public Map<TaskId, RuntimeException> drainUncaughtExceptions() {
356→        final Map<TaskId, RuntimeException> returnValue = returnWithTasksLocked(() -> {
357→            final Map<TaskId, RuntimeException> result = new HashMap<>(uncaughtExceptions);
358→            uncaughtExceptions.clear();
359→            return result;
360→        });
361→
362→        if (!returnValue.isEmpty()) {
363→            log.debug("Drained {} uncaught exceptions", returnValue.size());
364→        }
365→
366→        return returnValue;
367→    }
368→
369→    public boolean hasUncaughtException(final TaskId taskId) {
370→        return returnWithTasksLocked(() -> uncaughtExceptions.containsKey(taskId));
371→    }
372→
373→    private void executeWithTasksLocked(final Runnable action) {
374→        tasksLock.lock();
375→        try {
376→            action.run();
377→        } finally {
378→            tasksLock.unlock();
379→        }
380→    }
381→
382→    private <T> T returnWithTasksLocked(final Supplier<T> action) {
383→        tasksLock.lock();
384→        try {
385→            return action.get();
386→        } finally {
387→            tasksLock.unlock();
388→        }
389→    }
390→
391→    private boolean canProgress(final StreamTask task, final long nowMs) {
392→        return
393→            taskExecutionMetadata.canProcessTask(task, nowMs) && task.isProcessable(nowMs) ||
394→                taskExecutionMetadata.canPunctuateTask(task) && (task.canPunctuateStreamTime() || task.canPunctuateSystemTime());
395→    }
396→
397→    public void startTaskExecutors() {
398→        for (final TaskExecutor t: taskExecutors) {
399→            t.start();
400→        }
401→    }
402→
403→    public void shutdown(final Duration duration) {
404→        for (final TaskExecutor t: taskExecutors) {
405→            t.requestShutdown();
406→        }
407→        signalTaskExecutors();
408→        for (final TaskExecutor t: taskExecutors) {
409→            t.awaitShutdown(duration);
410→        }
411→    }
412→}
